'use client'

import Balancer from 'react-wrap-balancer'

import type { CtaProps } from '../../shared/cta'
import { Cta } from '../../shared/cta'

export interface Content07Props {
  items: {
    title?: string
    content?: string
    media?: {
      src: string
      alt: string
    }
    cta?: CtaProps
  }[]
}

export function Content07({ items }: Content07Props) {
  if (!items || items.length === 0) {
    return null
  }

  return (
    <div className="grid grid-cols-1 gap-8 md:grid-cols-2">
      {items.map((item, index) => (
        <div key={`${item.title}-${index}`} className="space-y-5">
          {item.media && (
            <div className="relative h-64 w-full overflow-hidden rounded-lg">
              <img
                src={item.media.src}
                alt={item.title ?? 'Content 07 image'}
                loading="lazy"
                decoding="async"
                className="absolute inset-0 size-full object-cover"
              />
            </div>
          )}

          <div className="space-y-2">
            {item.title && (
              <h3 className="text-xl font-medium">{item.title}</h3>
            )}
            {item.content && (
              <p className="text-muted-foreground whitespace-pre-line">
                <Balancer balance={0.5}>{item.content}</Balancer>
              </p>
            )}
          </div>

          {item.cta && <Cta cta={item.cta} />}
        </div>
      ))}
    </div>
  )
}

import {
  Content07,
  type Content07Props,
} from './content-07'

export const values = {
  items: [
    {
      title: 'From idea to interface',
      content:
        'Start with a clear concept. Turn it into a clean, focused layout without the clutter.',
      media: {
        src: 'https://images.unsplash.com/photo-1501027874987-73e9c32f46a0?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
        alt: 'Workspace with clean layout',
      },
      cta: {
        ctaEnabled: true,
        text: 'Learn more',
        link: '',
        variant: 'outline',
      },
    },
    {
      title: 'Ship with confidence',
      content:
        'Documented, consistent, and ready to adapt to your stack and your team.',
      media: {
        src: 'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=764&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D',
        alt: 'Developer at work',
      },
      cta: {
        ctaEnabled: true,
        text: 'Get started',
        link: '',
        variant: 'outline',
      },
    },
  ],
} satisfies Content07Props

export function Content07Example() {
  return <Content07 items={values.items} />
}
